def shortest_word(s):
    if not s:
        return ''

    words = s.split()
    shortest = min(words, key=len)

    # Find the last occurrence of the shortest word
    for i in range(len(words) - 1, -1, -1):
        if len(words[i]) == len(shortest):
            return words[i]
